from math import gcd

def solution(limit=12000):
    count = 0
    for d in range(1, limit + 1):
        # We need 1/3 < n/d < 1/2 => d/3 < n < d/2
        n_start = d // 3 + 1
        n_end = (d - 1) // 2
        for n in range(n_start, n_end + 1):
            if gcd(n, d) == 1:
                count += 1
    return count


if __name__ == "__main__":
    print(solution(12000))
